@@ -0,0 +1,23 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Sales Document Events (ID 30184).
+/// Handles events related to copying sales documents to clear Shopify-specific fields.
+/// </summary>
+codeunit 30184 "Shpfy Copy Sales Document Events"
+{
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesDocument', '', true, true)]
+    local procedure OnAfterCopySalesDocument(FromDocumentType: Option; FromDocumentNo: Code[20]; var ToSalesHeader: Record "Sales Header"; FromDocOccurenceNo: Integer; FromDocVersionNo: Integer; IncludeHeader: Boolean; RecalculateLines: Boolean; MoveNegLines: Boolean)
+    begin
+        // Clear Shopify Order Id and Shopify Order No. when copying a sales document
+        // This ensures that copied invoices can be re-exported to Shopify
+        if IncludeHeader and (ToSalesHeader."Document Type" = ToSalesHeader."Document Type"::Invoice) then begin
+            ToSalesHeader."Shpfy Order Id" := 0;
+            ToSalesHeader."Shpfy Order No." := '';
+            ToSalesHeader.Modify(false);
+        end;
+    end;
+}

